    public string UpdateBy { get; set; }
    public string Remark { get; set; }
    public bool IsDeleted { get; set; } = false;
}

public enum CustomerType
{
    Individual = "individual",
    Enterprise = "enterprise"
}

public enum CustomerStatus
{
    Active = "active",
    Inactive = "inactive",
