}
```

#### 3.1.2 供应商表（scm_supplier）
```sql
CREATE TABLE scm_supplier (
  id BIGINT PRIMARY KEY AUTO_INCREMENT COMMENT '主键ID',
  supplier_code VARCHAR(50) NOT NULL COMMENT '供应商编码',
  supplier_name VARCHAR(200) NOT NULL COMMENT '供应商名称',
