### 5.2 仓储实现
```csharp
// Infrastructure/Repositories/Repository.cs
using Kingdee.Cosmic.Core.Interfaces;
using Kingdee.Cosmic.Infrastructure.Data;
using Microsoft.EntityFrameworkCore;
using System.Linq.Expressions;

namespace Kingdee.Cosmic.Infrastructure.Repositories
{
    public class Repository<TEntity> : IRepository<TEntity> where TEntity : class
    {
        protected readonly ApplicationDbContext _context;
        protected readonly DbSet<TEntity> _dbSet;

        public Repository(ApplicationDbContext context)
        {
            _context = context;
            _dbSet = context.Set<TEntity>();
        }

        public virtual async Task<TEntity?> GetByIdAsync(long id)
        {
            return await _dbSet.FindAsync(id);
        }

        public virtual async Task<IReadOnlyList<TEntity>> GetAllAsync()
        {
            return await _dbSet.ToListAsync();
        }

        public virtual async Task<IReadOnlyList<TEntity>> GetPagedAsync(int page, int size)
        {
            return await _dbSet
                .Skip((page - 1) * size)
                .Take(size)
                .ToListAsync();
        }

        public virtual async Task<TEntity?> FindAsync(Expression<Func<TEntity, bool>> predicate)
        {
            return await _dbSet.FirstOrDefaultAsync(predicate);
        }

        public virtual async Task<IReadOnlyList<TEntity>> FindAllAsync(Expression<Func<TEntity, bool>> predicate)
        {
            return await _dbSet.Where(predicate).ToListAsync();
        }

        public virtual async Task<TEntity> AddAsync(TEntity entity)
        {
            await _dbSet.AddAsync(entity);
            await _context.SaveChangesAsync();
            return entity;
        }

        public virtual async Task<IReadOnlyList<TEntity>> AddRangeAsync(IReadOnlyList<TEntity> entities)
        {
            await _dbSet.AddRangeAsync(entities);
            await _context.SaveChangesAsync();
            return entities;
        }

        public virtual async Task UpdateAsync(TEntity entity)
        {
            _dbSet.Update(entity);
            await _context.SaveChangesAsync();
        }

        public virtual async Task UpdateRangeAsync(IReadOnlyList<TEntity> entities)
        {
            _dbSet.UpdateRange(entities);
            await _context.SaveChangesAsync();
        }

        public virtual async Task DeleteAsync(TEntity entity)
        {
            _dbSet.Remove(entity);
            await _context.SaveChangesAsync();
        }

        public virtual async Task DeleteRangeAsync(IReadOnlyList<TEntity> entities)
        {
            _dbSet.RemoveRange(entities);
            await _context.SaveChangesAsync();
        }

        public virtual async Task<bool> ExistsAsync(Expression<Func<TEntity, bool>> predicate)
        {
            return await _dbSet.AnyAsync(predicate);
        }

        public virtual async Task<int> CountAsync(Expression<Func<TEntity, bool>>? predicate = null)
        {
            var query = predicate == null ? _dbSet : _dbSet.Where(predicate);
            return await query.CountAsync();
        }
    }
}
```

### 5.3 具体仓储
```csharp
// Infrastructure/Repositories/VoucherRepository.cs
using Kingdee.Cosmic.Core.Finance.Entities;
using Kingdee.Cosmic.Core.Interfaces;
using Kingdee.Cosmic.Infrastructure.Data;
using Microsoft.EntityFrameworkCore;

namespace Kingdee.Cosmic.Infrastructure.Repositories
{
    public class VoucherRepository : Repository<Voucher>
    {
        public VoucherRepository(ApplicationDbContext context) : base(context)
        {
        }

        public async Task<Voucher?> GetByVoucherNoAsync(string voucherNo)
        {
            return await _dbSet
                .Include(v => v.Entries)
                .FirstOrDefaultAsync(v => v.VoucherNo == voucherNo && !v.IsDeleted);
        }

        public async Task<IReadOnlyList<Voucher>> GetPagedAsync(
            DateTime? startDate,
            DateTime? endDate,
            string? status,
            int page,
            int size)
        {
            var query = _dbSet.Where(v => !v.IsDeleted);

            if (startDate.HasValue)
            {
                query = query.Where(v => v.VoucherDate >= startDate.Value);
            }

            if (endDate.HasValue)
            {
                query = query.Where(v => v.VoucherDate <= endDate.Value);
            }

            if (!string.IsNullOrEmpty(status))
            {
                query = query.Where(v => v.Status == status);
            }

            return await query
                .OrderByDescending(v => v.VoucherDate)
                .Skip((page - 1) * size)
                .Take(size)
                .ToListAsync();
        }
    }
}
