### 6.3 应用服务实现
```csharp
// Application/Services/VoucherAppService.cs
using AutoMapper;
using Kingdee.Cosmic.Application.DTOs;
using Kingdee.Cosmic.Application.Interfaces;
using Kingdee.Cosmic.Core.Finance.Entities;
using Kingdee.Cosmic.Core.Interfaces;

namespace Kingdee.Cosmic.Application.Services
{
    public class VoucherAppService : IVoucherAppService
    {
        private readonly IVoucherRepository _voucherRepository;
        private readonly IAccountRepository _accountRepository;
        private readonly IMapper _mapper;
        private readonly ILogger<VoucherAppService> _logger;

        public VoucherAppService(
            IVoucherRepository voucherRepository,
            IAccountRepository accountRepository,
            IMapper mapper,
            ILogger<VoucherAppService> logger)
        {
            _voucherRepository = voucherRepository;
            _accountRepository = accountRepository;
            _mapper = mapper;
            _logger = logger;
        }

        public async Task<VoucherDto> GetByIdAsync(long id)
        {
            var voucher = await _voucherRepository.GetByVoucherNoAsync(id.ToString());
            if (voucher == null)
            {
                throw new NotFoundException($"凭证ID {id} 不存在");
            }

            return _mapper.Map<VoucherDto>(voucher);
        }

        public async Task<PagedResult<VoucherDto>> GetPagedAsync(VoucherQueryDto query)
        {
            var vouchers = await _voucherRepository.GetPagedAsync(
                query.StartDate,
                query.EndDate,
                query.Status,
                query.Page,
                query.Size);

            var dtos = _mapper.Map<List<VoucherDto>>(vouchers);

            return new PagedResult<VoucherDto>
            {
                Data = dtos,
                Page = query.Page,
                Size = query.Size,
                Total = await _voucherRepository.CountAsync()
            };
        }

        public async Task<VoucherDto> CreateAsync(CreateVoucherDto dto)
        {
            // 验证凭证号唯一性
            var existing = await _voucherRepository.GetByVoucherNoAsync(dto.VoucherNo);
            if (existing != null)
            {
                throw new BusinessException($"凭证号 {dto.VoucherNo} 已存在");
            }

            // 创建凭证实体
            var voucher = _mapper.Map<Voucher>(dto);
            voucher.Status = VoucherStatus.Draft;
            voucher.EntryCount = dto.Entries.Count;
            voucher.DebitAmount = dto.Entries.Sum(e => e.DebitAmount);
            voucher.CreditAmount = dto.Entries.Sum(e => e.CreditAmount);

            // 验证借贷平衡
            if (Math.Abs(voucher.DebitAmount - voucher.CreditAmount) > 0.01m)
            {
                throw new BusinessException("借方金额必须等于贷方金额");
            }

            // 保存凭证
            await _voucherRepository.AddAsync(voucher);

            _logger.LogInformation("创建凭证成功，凭证号：{VoucherNo}", dto.VoucherNo);

            return _mapper.Map<VoucherDto>(voucher);
        }

        public async Task<VoucherDto> UpdateAsync(long id, UpdateVoucherDto dto)
        {
            var voucher = await _voucherRepository.GetByIdAsync(id);
            if (voucher == null)
            {
                throw new NotFoundException($"凭证ID {id} 不存在");
            }

            if (voucher.Status != VoucherStatus.Draft)
            {
                throw new BusinessException("只有草稿状态的凭证可以修改");
            }

            if (dto.VoucherDate.HasValue)
            {
                voucher.VoucherDate = dto.VoucherDate.Value;
            }

            if (!string.IsNullOrEmpty(dto.Remark))
            {
                voucher.Remark = dto.Remark;
            }

            await _voucherRepository.UpdateAsync(voucher);

            return _mapper.Map<VoucherDto>(voucher);
        }

        public async Task DeleteAsync(long id)
        {
            var voucher = await _voucherRepository.GetByIdAsync(id);
            if (voucher == null)
            {
                throw new NotFoundException($"凭证ID {id} 不存在");
            }

            if (voucher.Status != VoucherStatus.Draft)
            {
                throw new BusinessException("只有草稿状态的凭证可以删除");
            }

            // 软删除
            voucher.IsDeleted = true;
            await _voucherRepository.UpdateAsync(voucher);

            _logger.LogInformation("删除凭证成功，凭证号：{VoucherNo}", voucher.VoucherNo);
        }

        public async Task AuditAsync(long id, string auditRemark)
        {
            var voucher = await _voucherRepository.GetByIdAsync(id);
            if (voucher == null)
            {
                throw new NotFoundException($"凭证ID {id} 不存在");
            }

            if (voucher.Status != VoucherStatus.Draft)
            {
                throw new BusinessException("只有草稿状态的凭证可以审核");
            }

            voucher.Status = VoucherStatus.Audited;
            voucher.AuditBy = "current_user"; // TODO: 从当前上下文获取
            voucher.AuditTime = DateTime.Now;

            await _voucherRepository.UpdateAsync(voucher);

            _logger.LogInformation("审核凭证成功，凭证号：{VoucherNo}", voucher.VoucherNo);
        }

        public async Task UnAuditAsync(long id, string unauditRemark)
        {
            var voucher = await _voucherRepository.GetByIdAsync(id);
            if (voucher == null)
            {
                throw new NotFoundException($"凭证ID {id} 不存在");
            }

            if (voucher.Status != VoucherStatus.Audited)
            {
                throw new BusinessException("只有已审核状态的凭证可以反审核");
            }

            voucher.Status = VoucherStatus.Draft;
            voucher.AuditBy = null;
            voucher.AuditTime = null;

            await _voucherRepository.UpdateAsync(voucher);

            _logger.LogInformation("反审核凭证成功，凭证号：{VoucherNo}", voucher.VoucherNo);
        }

        public async Task PostAsync(long id)
        {
            var voucher = await _voucherRepository.GetByIdAsync(id);
            if (voucher == null)
            {
                throw new NotFoundException($"凭证ID {id} 不存在");
            }

            if (voucher.Status != VoucherStatus.Audited)
            {
                throw new BusinessException("只有已审核状态的凭证可以过账");
            }

            // TODO: 过账逻辑，更新科目余额
            voucher.Status = VoucherStatus.Posted;
            voucher.PostBy = "current_user";
            voucher.PostTime = DateTime.Now;

            await _voucherRepository.UpdateAsync(voucher);

            _logger.LogInformation("过账凭证成功，凭证号：{VoucherNo}", voucher.VoucherNo);
        }

        public async Task UnPostAsync(long id, string unpostRemark)
        {
            var voucher = await _voucherRepository.GetByIdAsync(id);
            if (voucher == null)
            {
                throw new NotFoundException($"凭证ID {id} 不存在");
            }

            if (voucher.Status != VoucherStatus.Posted)
            {
                throw new BusinessException("只有已过账状态的凭证可以反过账");
            }

            // TODO: 反过账逻辑，回滚科目余额
            voucher.Status = VoucherStatus.Audited;
            voucher.PostBy = null;
            voucher.PostTime = null;

            await _voucherRepository.UpdateAsync(voucher);

            _logger.LogInformation("反过账凭证成功，凭证号：{VoucherNo}", voucher.VoucherNo);
        }
    }
}
