## 7. AutoMapper配置

### 7.1 Profile定义
```csharp
// Application/Profiles/VoucherProfile.cs
using AutoMapper;
using Kingdee.Cosmic.Application.DTOs;
using Kingdee.Cosmic.Core.Finance.Entities;

namespace Kingdee.Cosmic.Application.Profiles
{
    public class VoucherProfile : Profile
    {
        public VoucherProfile()
        {
            // 实体 -> DTO
            CreateMap<Voucher, VoucherDto>()
                .ForMember(d => d.Id, opt => opt.MapFrom(s => s.Id))
                .ForMember(d => d.VoucherNo, opt => opt.MapFrom(s => s.VoucherNo))
                .ForMember(d => d.VoucherDate, opt => opt.MapFrom(s => s.VoucherDate))
                .ForMember(d => d.VoucherType, opt => opt.MapFrom(s => s.VoucherType))
                .ForMember(d => d.Status, opt => opt.MapFrom(s => s.Status))
                .ForMember(d => d.EntryCount, opt => opt.MapFrom(s => s.EntryCount))
                .ForMember(d => d.DebitAmount, opt => opt.MapFrom(s => s.DebitAmount))
                .ForMember(d => d.CreditAmount, opt => opt.MapFrom(s => s.CreditAmount))
                .ForMember(d => d.CreateTime, opt => opt.MapFrom(s => s.CreateTime))
                .ForMember(d => d.CreateBy, opt => opt.MapFrom(s => s.CreateBy))
                .ForMember(d => d.Remark, opt => opt.MapFrom(s => s.Remark));

            // DTO -> 实体
            CreateMap<CreateVoucherDto, Voucher>()
                .ForMember(d => d.Id, opt => opt.Ignore())
                .ForMember(d => d.Status, opt => opt.MapFrom(s => VoucherStatus.Draft))
                .ForMember(d => d.CreateTime, opt => opt.MapFrom(s => DateTime.Now))
                .ForMember(d => d.UpdateTime, opt => opt.Ignore())
                .ForMember(d => d.CreateBy, opt => opt.MapFrom(s => "current_user"))
                .ForMember(d => d.UpdateBy, opt => opt.Ignore())
                .ForMember(d => d.IsDeleted, opt => opt.Ignore());

            CreateMap<UpdateVoucherDto, Voucher>()
                .ForAllMembers(opts => opts.Condition((src, dest, srcMember) => srcMember != null));

            CreateMap<CreateVoucherEntryDto, VoucherEntry>()
                .ForMember(d => d.Id, opt => opt.Ignore())
                .ForMember(d => d.VoucherId, opt => opt.Ignore())
                .ForMember(d => d.CreateTime, opt => opt.MapFrom(s => DateTime.Now))
                .ForMember(d => d.UpdateTime, opt => opt.Ignore())
                .ForMember(d => d.CreateBy, opt => opt.MapFrom(s => "current_user"))
                .ForMember(d => d.UpdateBy, opt => opt.Ignore())
                .ForMember(d => d.IsDeleted, opt => opt.Ignore());
        }
    }
}
