```csharp
// WebAPI/Controllers/BaseController.cs
using Kingdee.Cosmic.Application.DTOs;
using Microsoft.AspNetCore.Mvc;

namespace Kingdee.Cosmic.WebAPI.Controllers
{
    [ApiController]
    [Route("api/v1/[controller]")]
    public class BaseController : ControllerBase
    {
        protected IActionResult Ok<T>(T data, string message = "success")
        {
            return Ok(new ApiResponse<T>
            {
                Code = 200,
                Message = message,
                Data = data,
                Timestamp = DateTime.UtcNow
            });
        }

        protected IActionResult OkPaged<T>(PagedResult<T> data, string message = "success")
        {
            return Ok(new ApiResponse<PagedResult<T>>
            {
                Code = 200,
                Message = message,
                Data = data,
                Timestamp = DateTime.UtcNow
            });
        }

        protected IActionResult Error(string message, int code = 400)
        {
            return BadRequest(new ApiResponse
            {
                Code = code,
                Message = message,
                Timestamp = DateTime.UtcNow
            });
        }
    }

    public class ApiResponse
    {
        public int Code { get; set; }
        public string Message { get; set; } = null!;
        public DateTime Timestamp { get; set; }
    }

    public class ApiResponse<T> : ApiResponse
    {
        public T Data { get; set; } = default!;
    }
}
